# House Robber II — O(n) time, O(1) space
# KEY INSIGHT: circular means nums[0] and nums[n-1] are adjacent
# Split: run linear robber on [0..n-2] and [1..n-1], take max

def rob(nums):
    if len(nums) == 1:
        return nums[0]

    def robLinear(arr):
        prev2, prev1 = 0, 0
        for num in arr:
            curr = max(prev1, num + prev2)
            prev2, prev1 = prev1, curr
        return prev1

    # Either rob first house (exclude last) or last house (exclude first)
    return max(robLinear(nums[:-1]), robLinear(nums[1:]))
